1	/**
2	 * Centralized CLI UI module for Sequant
3	 *
4	 * Provides consistent styling, spinners, boxes, tables, and branding
5	 * with graceful fallbacks for non-TTY, CI, and legacy terminals.
6	 */
7	
8	import chalk from "chalk";
9	import ora, { type Ora } from "ora";
10	import boxen, { type Options as BoxenOptions } from "boxen";
11	// cli-table3 uses CommonJS `export =` syntax, default import works with esModuleInterop
12	import Table from "cli-table3";
13	import { isCI, isStdoutTTY } from "./tty.js";
14	
15	// ============================================================================
16	// Configuration
17	// ============================================================================
18	
19	/**
20	 * UI configuration options
21	 */
22	export interface UIConfig {
23	  /** Disable all colors and styling */
24	  noColor: boolean;
25	  /** JSON output mode - suppress decorative output */
26	  jsonMode: boolean;
27	  /** Verbose mode - use text-only spinners to avoid overwriting output */
28	  verbose: boolean;
29	  /** Whether stdout is a TTY */
30	  isTTY: boolean;
31	  /** Running in CI environment */
32	  isCI: boolean;
33	  /** Minimal output mode */
34	  minimal: boolean;
35	}
36	
37	/**
38	 * Global UI configuration state
39	 */
40	let config: UIConfig = {
41	  noColor: false,
42	  jsonMode: false,
43	  verbose: false,
44	  isTTY: isStdoutTTY(),
45	  isCI: isCI(),
46	  minimal: false,
47	};
48	
49	/**
50	 * Configure UI settings
51	 *
52	 * Call this early in CLI startup to set global options.
53	 */
54	export function configureUI(options: Partial<UIConfig>): void {
55	  config = { ...config, ...options };
56	
57	  // Check environment variables
58	  if (process.env.NO_COLOR || process.env.SEQUANT_MINIMAL === "1") {
59	    config.noColor = !!process.env.NO_COLOR;
60	    config.minimal = process.env.SEQUANT_MINIMAL === "1";
61	  }
62	
63	  // Auto-configure for CI
64	  if (config.isCI && !options.minimal) {
65	    config.minimal = true;
66	  }
67	}
68	
69	/**
70	 * Get current UI configuration
71	 */
72	export function getUIConfig(): Readonly<UIConfig> {
73	  return { ...config };
74	}
75	
76	/**
77	 * Check if decorative output should be shown
78	 */
79	function shouldShowDecorative(): boolean {
80	  return !config.jsonMode && !config.minimal && config.isTTY;
81	}
82	
83	/**
84	 * Check if animations should be used
85	 */
86	function shouldAnimate(): boolean {
87	  return (
88	    !config.jsonMode &&
89	    !config.verbose &&
90	    !config.isCI &&
91	    config.isTTY &&
92	    !config.noColor
93	  );
94	}
95	
96	// ============================================================================
97	// Color Palette
98	// ============================================================================
99	
100	/**
101	 * Standardized color palette for consistent styling
102	 */
103	export const colors = {
104	  // Semantic colors
105	  success: config.noColor ? (s: string) => s : chalk.green,
106	  error: config.noColor ? (s: string) => s : chalk.red,
107	  warning: config.noColor ? (s: string) => s : chalk.yellow,
108	  info: config.noColor ? (s: string) => s : chalk.blue,
109	  muted: config.noColor ? (s: string) => s : chalk.gray,
110	
111	  // UI elements
112	  header: config.noColor ? (s: string) => s : chalk.blue.bold,
113	  label: config.noColor ? (s: string) => s : chalk.cyan,
114	  value: config.noColor ? (s: string) => s : chalk.white,
115	  accent: config.noColor ? (s: string) => s : chalk.cyan,
116	  bold: config.noColor ? (s: string) => s : chalk.bold,
117	
118	  // Status colors
119	  pending: config.noColor ? (s: string) => s : chalk.gray,
120	  running: config.noColor ? (s: string) => s : chalk.cyan,
121	  completed: config.noColor ? (s: string) => s : chalk.green,
122	  failed: config.noColor ? (s: string) => s : chalk.red,
123	};
124	
125	/**
126	 * Get color function respecting current config
127	 */
128	function getColor(colorFn: (s: string) => string): (s: string) => string {
129	  return config.noColor ? (s: string) => s : colorFn;
130	}
131	
132	// ============================================================================
133	// Windows Compatibility
134	// ============================================================================
135	
136	/**
137	 * Detect if running on legacy Windows terminal
138	 */
139	function isLegacyWindows(): boolean {
140	  return (
141	    process.platform === "win32" &&
142	    !process.env.WT_SESSION && // Not Windows Terminal
143	    !process.env.TERM_PROGRAM // Not VS Code terminal
144	  );
145	}
146	
147	// ============================================================================
148	// ASCII Logo (Static - No figlet)
149	// ============================================================================
150	
151	/**
152	 * Static ASCII logo for SEQUANT branding
153	 * Clean, legible design inspired by the sequant logo
154	 * Q has distinctive tail like the brand logo
155	 */
156	const ASCII_LOGO = ` ██████  ███████   ██████   ██    ██   █████   ███    ██  ████████
157	██       ██       ██    ██  ██    ██  ██   ██  ████   ██     ██
158	 █████   █████    ██    ██  ██    ██  ███████  ██ ██  ██     ██
159	     ██  ██       ██ ▄▄ ██  ██    ██  ██   ██  ██  ██ ██     ██
160	██████   ███████   ██████    ██████   ██   ██  ██   ████     ██
161	                      ▀▀
162	`;
163	
164	/**
165	 * Get the ASCII logo with brand color
166	 */
167	export function logo(): string {
168	  if (config.jsonMode || config.minimal) return "";
169	  if (config.noColor || !config.isTTY) return ASCII_LOGO;
170	
171	  // Apply brand orange color
172	  return chalk.hex("#FF8012")(ASCII_LOGO);
173	}
174	
175	/**
176	 * Get the banner (logo + tagline)
177	 */
178	export function banner(): string {
179	  if (config.jsonMode || config.minimal) return "";
180	
181	  const logoText = logo();
182	  const tagline = config.noColor
183	    ? "  Quantize your development workflow"
184	    : chalk.gray("  Quantize your development workflow");
185	
186	  return `${logoText}\n${tagline}\n`;
187	}
188	
189	// ============================================================================
190	// Spinners
191	// ============================================================================
192	
193	/**
194	 * Spinner manager interface
195	 */
196	export interface SpinnerManager {
197	  /** Start the spinner with optional new text */
198	  start(text?: string): SpinnerManager;
199	  /** Mark as succeeded with optional message */
200	  succeed(text?: string): SpinnerManager;
201	  /** Mark as failed with optional message */
202	  fail(text?: string): SpinnerManager;
203	  /** Mark as warning with optional message */
204	  warn(text?: string): SpinnerManager;
205	  /** Stop the spinner */
206	  stop(): SpinnerManager;
207	  /** Update the spinner text */
208	  text: string;
209	  /** Check if spinner is active */
210	  isSpinning: boolean;
211	}
212	
213	/**
214	 * Text-only spinner for verbose mode / non-TTY
215	 */
216	class TextSpinner implements SpinnerManager {
217	  public text: string;
218	  public isSpinning = false;
219	
220	  constructor(initialText: string) {
221	    this.text = initialText;
222	  }
223	
224	  start(text?: string): SpinnerManager {
225	    if (text) this.text = text;
226	    this.isSpinning = true;
227	    if (!config.jsonMode) {
228	      console.log(getColor(chalk.cyan)(`\u23F3 ${this.text}`));
229	    }
230	    return this;
231	  }
232	
233	  succeed(text?: string): SpinnerManager {
234	    if (text) this.text = text;
235	    this.isSpinning = false;
236	    if (!config.jsonMode) {
237	      console.log(getColor(chalk.green)(`\u2713 ${this.text}`));
238	    }
239	    return this;
240	  }
241	
242	  fail(text?: string): SpinnerManager {
243	    if (text) this.text = text;
244	    this.isSpinning = false;
245	    if (!config.jsonMode) {
246	      console.log(getColor(chalk.red)(`\u2717 ${this.text}`));
247	    }
248	    return this;
249	  }
250	
251	  warn(text?: string): SpinnerManager {
252	    if (text) this.text = text;
253	    this.isSpinning = false;
254	    if (!config.jsonMode) {
255	      console.log(getColor(chalk.yellow)(`\u26A0 ${this.text}`));
256	    }
257	    return this;
258	  }
259	
260	  stop(): SpinnerManager {
261	    this.isSpinning = false;
262	    return this;
263	  }
264	}
265	
266	/**
267	 * Animated spinner wrapper
268	 */
269	class AnimatedSpinner implements SpinnerManager {
270	  private spinner: Ora;
271	
272	  constructor(initialText: string) {
273	    this.spinner = ora({
274	      text: initialText,
275	      color: "cyan",
276	      spinner: "dots",
277	    });
278	  }
279	
280	  get text(): string {
281	    return this.spinner.text;
282	  }
283	
284	  set text(value: string) {
285	    this.spinner.text = value;
286	  }
287	
288	  get isSpinning(): boolean {
289	    return this.spinner.isSpinning;
290	  }
291	
292	  start(text?: string): SpinnerManager {
293	    if (text) this.spinner.text = text;
294	    this.spinner.start();
295	    return this;
296	  }
297	
298	  succeed(text?: string): SpinnerManager {
299	    this.spinner.succeed(text);
300	    return this;
301	  }
302	
303	  fail(text?: string): SpinnerManager {
304	    this.spinner.fail(text);
305	    return this;
306	  }
307	
308	  warn(text?: string): SpinnerManager {
309	    this.spinner.warn(text);
310	    return this;
311	  }
312	
313	  stop(): SpinnerManager {
314	    this.spinner.stop();
315	    return this;
316	  }
317	}
318	
319	/**
320	 * Create a spinner with automatic fallback
321	 *
322	 * Returns an animated spinner for TTY, text-only for non-TTY/verbose/CI.
323	 */
324	export function spinner(text: string): SpinnerManager {
325	  if (shouldAnimate()) {
326	    return new AnimatedSpinner(text);
327	  }
328	  return new TextSpinner(text);
329	}
330	
331	// ============================================================================
332	// Boxes
333	// ============================================================================
334	
335	/**
336	 * Box style presets
337	 */
338	export type BoxStyle =
339	  | "success"
340	  | "error"
341	  | "warning"
342	  | "info"
343	  | "header"
344	  | "default";
345	
346	/**
347	 * Get boxen options for a given style
348	 */
349	function getBoxOptions(style: BoxStyle): BoxenOptions {
350	  const baseOptions: BoxenOptions = {
351	    padding: 1,
352	    borderStyle: isLegacyWindows() ? "classic" : "round",
353	  };
354	
355	  switch (style) {
356	    case "success":
357	      return {
358	        ...baseOptions,
359	        borderColor: config.noColor ? undefined : "green",
360	      };
361	    case "error":
362	      return {
363	        ...baseOptions,
364	        borderColor: config.noColor ? undefined : "red",
365	      };
366	    case "warning":
367	      return {
368	        ...baseOptions,
369	        borderColor: config.noColor ? undefined : "yellow",
370	      };
371	    case "info":
372	      return {
373	        ...baseOptions,
374	        borderColor: config.noColor ? undefined : "blue",
375	      };
376	    case "header":
377	      return {
378	        ...baseOptions,
379	        borderColor: config.noColor ? undefined : "cyan",
380	        padding: { top: 0, bottom: 0, left: 1, right: 1 },
381	      };
382	    default:
383	      return baseOptions;
384	  }
385	}
386	
387	/**
388	 * Create a boxed message
389	 */
390	export function box(content: string, style: BoxStyle = "default"): string {
391	  if (config.jsonMode) return "";
392	  if (!shouldShowDecorative()) {
393	    // Fallback to simple bordered output
394	    return content;
395	  }
396	
397	  return boxen(content, getBoxOptions(style));
398	}
399	
400	/**
401	 * Create a success box with title and message
402	 */
403	export function successBox(title: string, message: string): string {
404	  const content = `${getColor(chalk.green.bold)(`\u2705 ${title}`)}\n\n${message}`;
405	  return box(content, "success");
406	}
407	
408	/**
409	 * Create an error box with title and message
410	 */
411	export function errorBox(title: string, message: string): string {
412	  const content = `${getColor(chalk.red.bold)(`\u274C ${title}`)}\n\n${message}`;
413	  return box(content, "error");
414	}
415	
416	/**
417	 * Create a warning box with title and message
418	 */
419	export function warningBox(title: string, message: string): string {
420	  const content = `${getColor(chalk.yellow.bold)(`\u26A0\uFE0F  ${title}`)}\n\n${message}`;
421	  return box(content, "warning");
422	}
423	
424	/**
425	 * Create a header box
426	 */
427	export function headerBox(title: string): string {
428	  const content = getColor(chalk.bold)(title);
429	  return box(content, "header");
430	}
431	
432	// ============================================================================
433	// Tables
434	// ============================================================================
435	
436	/**
437	 * Table column definition
438	 */
439	export interface TableColumn {
440	  /** Column header text */
441	  header: string;
442	  /** Column width (optional) */
443	  width?: number;
444	  /** Text alignment */
445	  align?: "left" | "center" | "right";
446	}
447	
448	/**
449	 * Table options
450	 */
451	export interface TableOptions {
452	  /** Column definitions */
453	  columns: TableColumn[];
454	  /** Table style */
455	  style?: "default" | "compact" | "borderless";
456	}
457	
458	/**
459	 * Create a formatted table
460	 */
461	export function table(
462	  rows: (string | number)[][],
463	  options: TableOptions,
464	): string {
465	  if (config.jsonMode) return "";
466	
467	  const tableInstance = new Table({
468	    head: options.columns.map((col) =>
469	      config.noColor ? col.header : chalk.cyan.bold(col.header),
470	    ),
471	    colWidths: options.columns.map((col) => col.width ?? null),
472	    colAligns: options.columns.map((col) => col.align || "left"),
473	    style: {
474	      head: [],
475	      border: config.noColor ? [] : ["gray"],
476	    },
477	    chars: isLegacyWindows()
478	      ? {
479	          top: "-",
480	          "top-mid": "+",
481	          "top-left": "+",
482	          "top-right": "+",
483	          bottom: "-",
484	          "bottom-mid": "+",
485	          "bottom-left": "+",
486	          "bottom-right": "+",
487	          left: "|",
488	          "left-mid": "+",
489	          mid: "-",
490	          "mid-mid": "+",
491	          right: "|",
492	          "right-mid": "+",
493	          middle: "|",
494	        }
495	      : undefined,
496	  });
497	
498	  for (const row of rows) {
499	    tableInstance.push(row.map(String));
500	  }
501	
502	  return tableInstance.toString();
503	}
504	
505	/**
506	 * Create a simple key-value table
507	 */
508	export function keyValueTable(data: Record<string, string | number>): string {
509	  if (config.jsonMode) return "";
510	
511	  const rows = Object.entries(data).map(([key, value]) => [
512	    config.noColor ? key : chalk.cyan(key),
513	    String(value),
514	  ]);
515	
516	  const tableInstance = new Table({
517	    style: {
518	      head: [],
519	      border: config.noColor ? [] : ["gray"],
520	    },
521	    chars: isLegacyWindows()
522	      ? {
523	          top: "-",
524	          "top-mid": "+",
525	          "top-left": "+",
526	          "top-right": "+",
527	          bottom: "-",
528	          "bottom-mid": "+",
529	          "bottom-left": "+",
530	          "bottom-right": "+",
531	          left: "|",
532	          "left-mid": "+",
533	          mid: "-",
534	          "mid-mid": "+",
535	          right: "|",
536	          "right-mid": "+",
537	          middle: "|",
538	        }
539	      : undefined,
540	  });
541	
542	  for (const row of rows) {
543	    tableInstance.push(row);
544	  }
545	
546	  return tableInstance.toString();
547	}
548	
549	// ============================================================================
550	// Status Indicators
551	// ============================================================================
552	
553	/**
554	 * Status indicator types
555	 */
556	export type StatusType =
557	  | "success"
558	  | "error"
559	  | "warning"
560	  | "pending"
561	  | "running";
562	
563	/**
564	 * Get a status icon
565	 */
566	export function statusIcon(type: StatusType): string {
567	  if (config.noColor) {
568	    switch (type) {
569	      case "success":
570	        return "[OK]";
571	      case "error":
572	        return "[FAIL]";
573	      case "warning":
574	        return "[WARN]";
575	      case "pending":
576	        return "[ ]";
577	      case "running":
578	        return "[..]";
579	    }
580	  }
581	
582	  switch (type) {
583	    case "success":
584	      return chalk.green("\u2713");
585	    case "error":
586	      return chalk.red("\u2717");
587	    case "warning":
588	      return chalk.yellow("\u26A0");
589	    case "pending":
590	      return chalk.gray("\u25CB");
591	    case "running":
592	      return chalk.cyan("\u25D0");
593	  }
594	}
595	
596	/**
597	 * Print a status message with icon
598	 */
599	export function printStatus(type: StatusType, message: string): void {
600	  if (config.jsonMode) return;
601	  console.log(`${statusIcon(type)} ${message}`);
602	}
603	
604	// ============================================================================
605	// Layout Utilities
606	// ============================================================================
607	
608	/**
609	 * Create a horizontal divider
610	 */
611	export function divider(width = 50): string {
612	  if (config.jsonMode) return "";
613	
614	  const char = isLegacyWindows() ? "-" : "\u2501";
615	  const line = char.repeat(width);
616	  return config.noColor ? line : chalk.gray(line);
617	}
618	
619	/**
620	 * Create a section header
621	 */
622	export function sectionHeader(title: string): string {
623	  if (config.jsonMode) return "";
624	
625	  const formattedTitle = config.noColor ? title : chalk.blue.bold(title);
626	  return `\n${formattedTitle}\n${divider(title.length + 4)}\n`;
627	}
628	
629	// ============================================================================
630	// Progress & Phase Visualization
631	// ============================================================================
632	
633	/**
634	 * Phase status for progress display
635	 */
636	export interface PhaseStatus {
637	  name: string;
638	  status: "pending" | "running" | "success" | "failure" | "skipped";
639	}
640	
641	/**
642	 * Display phase progress as a visual indicator
643	 */
644	export function phaseProgress(phases: PhaseStatus[]): string {
645	  if (config.jsonMode) return "";
646	
647	  const icons = phases.map((phase) => {
648	    switch (phase.status) {
649	      case "success":
650	        return config.noColor ? "[OK]" : chalk.green("\u25CF");
651	      case "failure":
652	        return config.noColor ? "[X]" : chalk.red("\u2717");
653	      case "running":
654	        return config.noColor ? "[..]" : chalk.cyan("\u25D0");
655	      case "skipped":
656	        return config.noColor ? "[-]" : chalk.gray("-");
657	      default:
658	        return config.noColor ? "[ ]" : chalk.gray("\u25CB");
659	    }
660	  });
661	
662	  const labels = phases.map((phase) => phase.name.charAt(0).toUpperCase());
663	
664	  return `  Phases: ${icons.join(" ")}\n          ${labels.join(" ")}`;
665	}
666	
667	/**
668	 * Create a progress bar
669	 */
670	export function progressBar(
671	  current: number,
672	  total: number,
673	  width = 20,
674	): string {
675	  if (config.jsonMode) return "";
676	
677	  const percentage = total > 0 ? current / total : 0;
678	  const filled = Math.round(percentage * width);
679	  const empty = width - filled;
680	
681	  const filledChar = config.noColor || isLegacyWindows() ? "#" : "\u2588";
682	  const emptyChar = config.noColor || isLegacyWindows() ? "-" : "\u2591";
683	
684	  const bar = filledChar.repeat(filled) + emptyChar.repeat(empty);
685	  return config.noColor
686	    ? bar
687	    : chalk.green(filledChar.repeat(filled)) +
688	        chalk.gray(emptyChar.repeat(empty));
689	}
690	
691	// ============================================================================
692	// Unified UI Namespace
693	// ============================================================================
694	
695	/**
696	 * Unified UI object for convenient access to all utilities
697	 */
698	export const ui = {
699	  // Config
700	  configure: configureUI,
701	  getConfig: getUIConfig,
702	
703	  // Branding
