import { extractAcceptanceCriteria } from './src/lib/ac-parser.ts';
import { StateManager } from './src/lib/workflow/state-manager.ts';

const issueBody = \`## Acceptance Criteria

- [ ] **Parallel mode**: Phase progress uses ora-consistent symbols; no \\\`●\\\` bullets or \\\`⏳\\\` emoji
- [ ] **Parallel mode**: Heartbeat interval increased to 5m or suppressed when phase events occur within window
- [ ] **Parallel mode**: Progress line uses new icon set (\\\`✔\\\`/\\\`▸\\\`/\\\`·\\\`), no emoji
- [ ] **Header**: \\\`headerBox()\\\` produces a bold title without boxen borders
- [ ] **Divider**: \\\`divider()\\\` uses light \\\`─\\\` (U+2500) instead of heavy \\\`━\\\` (U+2501)
- [ ] **Status icons**: \\\`statusIcon()\\\` returns ora-consistent symbols across all types
- [ ] **Config display**: Key-value pairs in run command use columnar alignment
- [ ] **Summary**: Light divider, no emoji in log/tip lines
- [ ] **All commands**: No decorative emoji (📦🔄📢📝🌐🔍📊💡📂✅) in structured output
- [ ] **Sequential/chain mode**: No regression — already-clean display stays clean
- [ ] **No-color mode**: All new symbols have text fallbacks
- [ ] **CI mode**: Minimal output still works
- [ ] **Non-TTY**: Text spinners use updated icon set
- [ ] Existing tests pass; update snapshot tests if any\`;

const ac = extractAcceptanceCriteria(issueBody);
console.log('Extracted AC:', JSON.stringify(ac, null, 2));

if (ac.items.length > 0) {
  const manager = new StateManager();
  (async () => {
    const existing = await manager.getIssueState(495);
    if (!existing) {
      await manager.initializeIssue(495, 'Modernize CLI output formatting across all commands');
    }
    await manager.updateAcceptanceCriteria(495, ac);
    console.log('AC stored in state for issue #495');
  })();
}
" 2>&1

