import { parseAcceptanceCriteria } from './src/lib/ac-parser.ts';
import { performScopeAssessment, formatScopeAssessment, convertSettingsToConfig } from './src/lib/scope/index.ts';
import { getSettings } from './src/lib/settings.ts';

const issueBody = \`## Summary
Modernize CLI output formatting across all commands.

## Acceptance Criteria
- [ ] Parallel mode: Phase progress uses ora-consistent symbols
- [ ] Parallel mode: Heartbeat interval increased to 5m
- [ ] Parallel mode: Progress line uses new icon set
- [ ] Header: headerBox() produces bold title without boxen borders
- [ ] Divider: divider() uses light rule
- [ ] Status icons: statusIcon() returns ora-consistent symbols
- [ ] Config display: columnar alignment
- [ ] Summary: Light divider, no emoji
- [ ] All commands: No decorative emoji
- [ ] Sequential/chain mode: No regression
- [ ] No-color mode: text fallbacks
- [ ] CI mode: Minimal output still works
- [ ] Non-TTY: updated icon set
- [ ] Existing tests pass
\`;

(async () => {
  const settings = await getSettings();
  const config = convertSettingsToConfig(settings.scopeAssessment);
  const criteria = parseAcceptanceCriteria(issueBody);
  const assessment = performScopeAssessment(criteria, issueBody, 'Modernize CLI output formatting across all commands', config);
  console.log(formatScopeAssessment(assessment));
})();
" 2>&1

