/**
 * Status indicator types
 */
export type StatusType =
  | "success"
  | "error"
  | "warning"
  | "pending"
  | "running";

/**
 * Get a status icon
 */
export function statusIcon(type: StatusType): string {
  if (config.noColor) {
    switch (type) {
      case "success":
        return "[OK]";
      case "error":
        return "[FAIL]";
      case "warning":
        return "[WARN]";
      case "pending":
        return "[ ]";
      case "running":
        return "[..]";
    }
  }

  switch (type) {
    case "success":
      return chalk.green("\u2713");
    case "error":
      return chalk.red("\u2717");
    case "warning":
      return chalk.yellow("\u26A0");
    case "pending":
      return chalk.gray("\u25CB");
    case "running":
      return chalk.cyan("\u25D0");
  }
}

/**
 * Print a status message with icon
 */
export function printStatus(type: StatusType, message: string): void {
  if (config.jsonMode) return;
  console.log(`${statusIcon(type)} ${message}`);
}

