/**
 * Phase execution engine for workflow orchestration.
 *
 * Handles executing individual phases via an AgentDriver interface,
 * including cold-start retry logic and MCP fallback strategies.
 *
 * The SDK import has been moved to ClaudeCodeDriver — this module
 * is agent-agnostic.
 */

import chalk from "chalk";
import { execSync } from "child_process";
import { ShutdownManager } from "../shutdown.js";
import { PhaseSpinner } from "../phase-spinner.js";
import { Phase, ExecutionConfig, PhaseResult, QaVerdict } from "./types.js";
import type { QaSummary } from "./run-log-schema.js";
import { readAgentsMd } from "../agents-md.js";
import { getDriver } from "./drivers/index.js";
import type { AgentDriver, AgentExecutionConfig } from "./drivers/index.js";

/**
 * Natural language prompts for each phase.
 * Claude Code invokes the corresponding skills via natural language.
 */
const PHASE_PROMPTS: Record<Phase, string> = {
  spec: "Review GitHub issue #{issue} and create an implementation plan with verification criteria. Run the /spec {issue} workflow.",
  "security-review":
    "Perform a deep security analysis for GitHub issue #{issue} focusing on auth, permissions, and sensitive operations. Run the /security-review {issue} workflow.",
  testgen:
    "Generate test stubs for GitHub issue #{issue} based on the specification. Run the /testgen {issue} workflow.",
  exec: "Implement the feature for GitHub issue #{issue} following the spec. Run the /exec {issue} workflow.",
  test: "Execute structured browser-based testing for GitHub issue #{issue}. Run the /test {issue} workflow.",
  verify:
    "Verify the implementation for GitHub issue #{issue} by running commands and capturing output. Run the /verify {issue} workflow.",
  qa: "Review the implementation for GitHub issue #{issue} against acceptance criteria. Run the /qa {issue} workflow.",
  loop: "Parse test/QA findings for GitHub issue #{issue} and iterate until quality gates pass. Run the /loop {issue} workflow.",
  merger:
    "Integrate and merge completed worktrees for GitHub issue #{issue}. Run the /merger {issue} workflow.",
};

/**
 * Self-contained prompts for non-Claude agents (Aider, Codex, etc.).
 * These agents don't have a skill system, so prompts must include
 * full instructions rather than skill invocations.
 */
const AIDER_PHASE_PROMPTS: Record<Phase, string> = {
  spec: `Read GitHub issue #{issue} using 'gh issue view #{issue}'.
Create a spec comment on the issue with:
1. Implementation plan
2. Acceptance criteria as a checklist
3. Risk assessment
Post the comment using 'gh issue comment #{issue} --body "<comment>"'.`,
  "security-review": `Perform a security review for GitHub issue #{issue}.
Read the issue with 'gh issue view #{issue}'.
Check for auth, permissions, injection, and sensitive data issues.
Post findings as a comment on the issue.`,
  testgen: `Generate test stubs for GitHub issue #{issue}.
Read the spec comments on the issue with 'gh issue view #{issue} --comments'.
Create test files with describe/it blocks covering the acceptance criteria.
Use the project's existing test framework.`,
  exec: `Implement the feature described in GitHub issue #{issue}.
Read the issue and any spec comments with 'gh issue view #{issue} --comments'.
Follow the implementation plan from the spec.
Write tests for new functionality.
Ensure the build passes with 'npm test' and 'npm run build'.`,
  test: `Test the implementation for GitHub issue #{issue}.
Run 'npm test' and verify all tests pass.
Check for edge cases and error handling.`,
  verify: `Verify the implementation for GitHub issue #{issue}.
Run relevant commands and capture their output for review.`,
  qa: `Review the changes for GitHub issue #{issue}.
Run 'npm test' and 'npm run build' to verify everything works.
Check each acceptance criterion from the issue comments.
Output a verdict: READY_FOR_MERGE, AC_MET_BUT_NOT_A_PLUS, or AC_NOT_MET
with format "### Verdict: <VERDICT>" followed by an explanation.`,
  loop: `Review test and QA findings for GitHub issue #{issue}.
Fix any issues identified in the QA feedback.
Re-run 'npm test' and 'npm run build' until all quality gates pass.`,
  merger: `Integrate and merge completed worktrees for GitHub issue #{issue}.
Ensure all branches are up to date and merge cleanly.`,
};

/**
 * Phases that require worktree isolation.
 * Only `spec` runs in the main repo (planning-only, no file changes).
 * All other phases must run in the worktree because:
 * 1. They need to read/modify the worktree code
 * 2. Resuming a session created in a different cwd crashes the SDK
 */
const ISOLATED_PHASES: Phase[] = [
  "exec",
  "security-review",
  "testgen",
  "test",
  "qa",
  "loop",
];

/**
 * Cold-start retry threshold in seconds.
 * Failures under this duration are likely Claude Code subprocess initialization
 * issues rather than genuine phase failures (based on empirical data: cold-start
 * failures consistently complete in 15-39s vs 150-310s for real work).
 */
const COLD_START_THRESHOLD_SECONDS = 60;
const COLD_START_MAX_RETRIES = 2;

/**
 * Spec-specific retry configuration.
 * Spec failures have a higher failure rate (~8.6%) than other phases due to
 * transient GitHub API issues and rate limits. One extra retry with backoff
 * recovers most of these without user intervention.
 */
/** @internal Exported for testing only */
export const SPEC_RETRY_BACKOFF_MS = 5000;
/** @internal Exported for testing only */
export const SPEC_EXTRA_RETRIES = 1;

export function parseQaVerdict(output: string): QaVerdict | null {
  if (!output) return null;

  // Match various verdict formats:
  // - "### Verdict: X" (markdown header)
  // - "**Verdict:** X" (bold label with colon inside)
  // - "**Verdict:** **X**" (bold label and bold value)
  // - "Verdict: X" (plain)
  // Case insensitive, handles optional markdown formatting
  const verdictMatch = output.match(
    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
  );

  if (!verdictMatch) return null;

  // Normalize to uppercase with underscores
  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
  return verdict;
}

/**
 * Parse condensed QA summary from QA phase output (#434).
 *
 * Handles multiple AC table formats produced by the QA skill:
 * - 5-column: | AC-N | source | desc | STATUS | notes |
 * - 4-column: | AC-N | desc | STATUS | notes |
 * - 3-column: | AC-N | desc | STATUS |
 *
 * Status cells may contain emoji prefixes (✅ MET), shorthand
 * (PARTIAL), or trailing text (MET — explanation).
 *
 * @internal Exported for testing only
 */
export function parseQaSummary(output: string): QaSummary | null {
  if (!output) return null;

  // Anchored pattern: cell content starts with optional emoji, then status keyword
  // Uses alternation (not character class) to avoid ESLint no-misleading-character-class
  const STATUS_CELL =
    /^(?:\u2705|\u274C|\u26A0\uFE0F|\u2B50|\u2139\uFE0F|\u2753|\u2757)?\s*(MET|NOT_MET|PARTIALLY_MET|PARTIAL|PENDING|N\/A)\b/i;

  const lines = output.split("\n");
  const acRows = lines.filter((line) => /^\s*\|\s*\*?\*?AC-\d+/.test(line));

  if (acRows.length === 0) return null;

  let acMet = 0;
  let acTotal = 0;

  for (const row of acRows) {
    const cells = row
      .split("|")
      .map((c) => c.trim())
      .filter(Boolean);

    // Scan cells right-to-left to find the status cell
    let found = false;
    for (let i = cells.length - 1; i >= 1; i--) {
      const match = cells[i].match(STATUS_CELL);
      if (match) {
        const status = match[1].toUpperCase();
        acTotal++;
        if (status === "MET") acMet++;
        found = true;
        break;
      }
    }
    // Row with AC-N but no parseable status is skipped
    if (!found) continue;
  }

  if (acTotal === 0) return null;

  const gaps = parseListSection(output, /\*\*(?:Issues|Gaps)/);
  const suggestions = parseListSection(output, /\*\*Suggestions/);

  return { acMet, acTotal, gaps, suggestions };
}

/**
 * Parse a markdown bullet list section, filtering out "None" variants.
 */
function parseListSection(output: string, headerPattern: RegExp): string[] {
  const items: string[] = [];
  const lines = output.split("\n");

  let inSection = false;
  for (const line of lines) {
    if (headerPattern.test(line)) {
      // If the header line itself contains a bullet (inline), capture it
      inSection = true;
      continue;
    }

    if (inSection) {
      // Section ends at next markdown header or bold label
      if (/^#{1,4}\s/.test(line) || /^\*\*[^*]+\*\*:/.test(line)) {
        break;
      }

      const bulletMatch = line.match(/^\s*[-*]\s+(.+)/);
      if (bulletMatch) {
        const trimmed = bulletMatch[1].trim();
        // Filter "None", "None found", "None — text", etc.
        if (trimmed && !/^None\b/i.test(trimmed)) {
          items.push(trimmed);
        }
      } else if (line.trim() === "") {
        continue;
      } else {
        break;
      }
    }
  }

  return items;
}

/**
 * Format duration in human-readable format
 */
export function formatDuration(seconds: number): string {
  if (seconds < 60) {
    return `${seconds.toFixed(1)}s`;
  }
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}m ${secs.toFixed(0)}s`;
}

/**
 * Get the prompt for a phase with the issue number substituted.
 * Selects self-contained prompts for non-Claude agents.
 * Includes AGENTS.md content as context so non-Claude agents
 * receive project conventions and workflow instructions.
 *
 * @internal Exported for testing only
 */
export async function getPhasePrompt(
  phase: Phase,
  issueNumber: number,
  agent?: string,
  promptContext?: string,
): Promise<string> {
  const prompts =
    agent && agent !== "claude-code" ? AIDER_PHASE_PROMPTS : PHASE_PROMPTS;
  let basePrompt = prompts[phase].replace(/\{issue\}/g, String(issueNumber));

  // Append phase-specific context (e.g., QA findings for loop phase)
  if (promptContext) {
    basePrompt += `\n\n---\n\n${promptContext}`;
  }

  // Include AGENTS.md content in the prompt context for non-Claude agent compatibility.
  // Claude reads CLAUDE.md natively, but other agents (Aider, Codex, Gemini CLI)
  // rely on AGENTS.md for project context.
  const agentsMd = await readAgentsMd();
  if (agentsMd) {
    return `Project context (from AGENTS.md):\n\n${agentsMd}\n\n---\n\n${basePrompt}`;
  }

  return basePrompt;
}

/**
 * Execute a single phase for an issue using the configured AgentDriver.
 */
async function executePhase(
  issueNumber: number,
  phase: Phase,
  config: ExecutionConfig,
  sessionId?: string,
  worktreePath?: string,
  shutdownManager?: ShutdownManager,
  spinner?: PhaseSpinner,
): Promise<PhaseResult & { sessionId?: string }> {
  const startTime = Date.now();

  const prompt = await getPhasePrompt(
    phase,
    issueNumber,
    config.agent,
    config.promptContext,
  );

  if (config.dryRun) {
    // Dry run - show the prompt that would be sent, then return
    if (config.verbose) {
      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
      console.log(chalk.gray(`    Prompt: ${prompt}`));
    }
    return {
      phase,
      success: true,
      durationSeconds: 0,
      output: prompt,
    };
  }

  if (config.verbose) {
    console.log(chalk.gray(`    Prompt: ${prompt}`));
    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
    }
  }

  // Determine working directory and environment
  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
  const cwd = shouldUseWorktree ? worktreePath : process.cwd();

  // Resolve file context for file-oriented drivers (e.g., Aider --file)
  let files: string[] | undefined;
  if (config.agent && config.agent !== "claude-code") {
    try {
      const output = execSync("git diff --name-only main...HEAD", {
        cwd,
        encoding: "utf-8",
        stdio: ["pipe", "pipe", "pipe"],
      }).trim();
      if (output) {
        files = output.split("\n").filter(Boolean);
      }
    } catch {
      // No changed files or git error — proceed without file context
    }
  }

  // Check if shutdown is in progress
  if (shutdownManager?.shuttingDown) {
    return {
      phase,
      success: false,
      durationSeconds: 0,
      error: "Shutdown in progress",
    };
  }

  // Create abort controller for timeout
  const abortController = new AbortController();
  const timeoutId = setTimeout(() => {
    abortController.abort();
  }, config.phaseTimeout * 1000);

  // Register abort controller with shutdown manager for graceful shutdown
  // Uses add/remove to support concurrent phase execution (#404)
  if (shutdownManager) {
    shutdownManager.addAbortController(abortController);
  }

  // Build environment with worktree isolation variables
  const env: Record<string, string> = {
    ...process.env,
    CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
  };

  // Set worktree isolation environment variables
  if (shouldUseWorktree) {
    env.SEQUANT_WORKTREE = worktreePath;
    env.SEQUANT_ISSUE = String(issueNumber);
  }

  // Set orchestration context for skills to detect they're part of a workflow
  // Skills can check these to skip redundant pre-flight checks
  env.SEQUANT_ORCHESTRATOR = "sequant-run";
  env.SEQUANT_PHASE = phase;

  // Propagate issue type for skills to adapt behavior (e.g., lighter QA for docs)
  if (config.issueType) {
    env.SEQUANT_ISSUE_TYPE = config.issueType;
  }

  // Pass QA context to loop phase so it doesn't need to reconstruct from GitHub (#488)
  if (config.lastVerdict) {
    env.SEQUANT_LAST_VERDICT = config.lastVerdict;
  }
  if (config.failedAcs) {
    env.SEQUANT_FAILED_ACS = config.failedAcs;
  }

  // Track whether we're actively streaming verbose output
  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
  // (Issue #283: ora's stop() clears the current line, which can truncate output when
  // pause/resume is called for every chunk in rapid succession)
  let verboseStreamingActive = false;

  // Safety: never resume a session when worktree isolation is active.
  // Even if THIS phase doesn't use the worktree, a previous phase may have
  // created the session there. Resuming from a different cwd crashes the SDK
  // (exit code 1). ISOLATED_PHASES prevents this by design, but this guard
  // catches edge cases (e.g. a new phase added without updating ISOLATED_PHASES).
  const canResume = sessionId && !worktreePath;

  // Build AgentExecutionConfig for the driver
  const agentConfig: AgentExecutionConfig = {
    cwd,
    env,
    abortSignal: abortController.signal,
    phaseTimeout: config.phaseTimeout,
    verbose: config.verbose,
    mcp: config.mcp,
    sessionId: canResume ? sessionId : undefined,
    files,
    onOutput: config.verbose
      ? (text: string) => {
          if (!verboseStreamingActive) {
            spinner?.pause();
            verboseStreamingActive = true;
          }
          process.stdout.write(chalk.gray(text));
        }
      : undefined,
    onStderr: config.verbose
      ? (data: string) => {
          if (!verboseStreamingActive) {
            spinner?.pause();
            verboseStreamingActive = true;
          }
          process.stderr.write(chalk.red(data));
        }
      : undefined,
  };

  // Resolve driver from config or default
  const driver: AgentDriver = getDriver(config.agent, {
    aiderSettings: config.aiderSettings,
  });

  const agentResult = await driver.executePhase(prompt, agentConfig);

  // Resume spinner after execution completes (if we paused it)
  if (verboseStreamingActive) {
    spinner?.resume();
  }

  clearTimeout(timeoutId);

  // Remove this specific abort controller from shutdown manager
  if (shutdownManager) {
    shutdownManager.removeAbortController(abortController);
  }

  const durationSeconds = (Date.now() - startTime) / 1000;

  // Map AgentPhaseResult to PhaseResult
  const tails = {
    stderrTail: agentResult.stderrTail,
    stdoutTail: agentResult.stdoutTail,
    exitCode: agentResult.exitCode,
  };

  if (agentResult.success) {
    // For QA phase, check the verdict to determine actual success
    // Agent "success" just means the execution completed — we need to parse the verdict
    if (phase === "qa" && agentResult.output) {
      const verdict = parseQaVerdict(agentResult.output);
      const summary = parseQaSummary(agentResult.output) ?? undefined;
      if (
        verdict &&
        verdict !== "READY_FOR_MERGE" &&
        verdict !== "NEEDS_VERIFICATION"
      ) {
        return {
          phase,
          success: false,
          durationSeconds,
          error: `QA verdict: ${verdict}`,
          sessionId: agentResult.sessionId,
          output: agentResult.output,
          verdict,
          summary,
          ...tails,
        };
      }
      return {
        phase,
        success: true,
        durationSeconds,
        sessionId: agentResult.sessionId,
        output: agentResult.output,
        verdict: verdict ?? undefined,
        summary,
        ...tails,
      };
    }

    return {
      phase,
      success: true,
      durationSeconds,
      sessionId: agentResult.sessionId,
      output: agentResult.output,
      ...tails,
    };
  }

  return {
    phase,
    success: false,
    durationSeconds,
    error: agentResult.error,
    sessionId: agentResult.sessionId,
    ...tails,
  };
}

/**
 * Execute a phase with automatic retry for cold-start failures and MCP fallback.
 *
 * Retry strategy:
 * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
 * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
 *    can fail on first run due to cold-cache issues)
 *
 * The MCP fallback is safe because MCP servers are optional enhancements, not required
 * for core functionality.
 */
/**
 * @internal Exported for testing only
 */
export async function executePhaseWithRetry(
  issueNumber: number,
  phase: Phase,
  config: ExecutionConfig,
  sessionId?: string,
  worktreePath?: string,
  shutdownManager?: ShutdownManager,
  spinner?: PhaseSpinner,
  /** @internal Injected for testing — defaults to module-level executePhase */
  executePhaseFn: typeof executePhase = executePhase,
  /** @internal Injected for testing — defaults to setTimeout-based delay */
  delayFn: (ms: number) => Promise<void> = (ms) =>
    new Promise((resolve) => setTimeout(resolve, ms)),
): Promise<PhaseResult & { sessionId?: string }> {
  // Skip retry logic if explicitly disabled
  if (config.retry === false) {
    return executePhaseFn(
      issueNumber,
      phase,
      config,
      sessionId,
      worktreePath,
      shutdownManager,
      spinner,
    );
  }

  // Skip cold-start retries for `loop` phase (#488).
  // Loop is always a re-run after a failed QA — never a first boot.
  // Failures at 47-51s are genuine skill failures, not cold-start issues.
  // Without this guard, 2 cold-start retries + 1 MCP fallback = 3 wasted spawns per loop.
  const skipColdStartRetry = phase === "loop";

  let lastResult: PhaseResult & { sessionId?: string };

  if (skipColdStartRetry) {
    // Single attempt — no cold-start retry loop
    lastResult = await executePhaseFn(
      issueNumber,
      phase,
      config,
      sessionId,
      worktreePath,
      shutdownManager,
      spinner,
    );

    if (lastResult.success) {
      return lastResult;
    }
  } else {
    // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
    for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
      lastResult = await executePhaseFn(
        issueNumber,
        phase,
        config,
        sessionId,
        worktreePath,
        shutdownManager,
        spinner,
      );

      const duration = lastResult.durationSeconds ?? 0;

      // Success → return immediately
      if (lastResult.success) {
        return lastResult;
      }

      // Genuine failure (took long enough to be real work) → skip cold-start retries.
      // For spec phase, break to allow Phase 3 (spec-specific retry) to run.
      // For other phases, return immediately — no further retries.
      if (duration >= COLD_START_THRESHOLD_SECONDS) {
        if (phase === "spec") {
          break;
        }
        return lastResult;
      }

      // Cold-start failure detected — retry
      if (attempt < COLD_START_MAX_RETRIES) {
        if (config.verbose) {
          console.log(
            chalk.yellow(
              `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
            ),
          );
        }
      }
    }
  }

  // Capture the original error for better diagnostics
  const originalError = lastResult!.error;

  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
  // This handles npx-based MCP servers that fail on first run due to cold-cache issues.
  // Skip for `loop` phase — MCP is never the cause of loop failures (#488).
  if (config.mcp && !lastResult!.success && !skipColdStartRetry) {
    console.log(
      chalk.yellow(
        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
      ),
    );

    // Create config copy with MCP disabled
    const configWithoutMcp: ExecutionConfig = {
      ...config,
      mcp: false,
    };

    const retryResult = await executePhaseFn(
      issueNumber,
      phase,
      configWithoutMcp,
      sessionId,
      worktreePath,
      shutdownManager,
      spinner,
    );

    if (retryResult.success) {
      console.log(
        chalk.green(
          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
        ),
      );
      return retryResult;
    }

    // Update lastResult for Phase 3 (spec retry)
    lastResult = retryResult;

    // Non-spec phases: return original error after MCP fallback exhausted
    if (phase !== "spec") {
      return {
        ...lastResult!,
        error: originalError,
      };
    }
  }

  // Phase 3: Spec-specific retry — spec has a higher transient failure rate
  // than other phases (~8.6%), so one extra retry with backoff recovers most cases.
  if (phase === "spec" && !lastResult!.success) {
    for (let i = 0; i < SPEC_EXTRA_RETRIES; i++) {
      console.log(
        chalk.yellow(
          `\n    ⟳ Spec phase failed, retrying with ${SPEC_RETRY_BACKOFF_MS}ms backoff... (spec retry ${i + 1}/${SPEC_EXTRA_RETRIES})`,
        ),
      );

      await delayFn(SPEC_RETRY_BACKOFF_MS);

      const specRetryResult = await executePhaseFn(
        issueNumber,
        phase,
        config,
        sessionId,
        worktreePath,
        shutdownManager,
        spinner,
      );

      if (specRetryResult.success) {
        console.log(chalk.green(`    ✓ Spec phase succeeded on retry`));
        return specRetryResult;
      }

      lastResult = specRetryResult;
    }

    // All spec retries exhausted — return with original error for diagnostics
    return {
      ...lastResult!,
      error: originalError,
    };
  }

  return lastResult!;
}

/**
 * State cleanup and reconciliation utilities
 *
 * @module state-cleanup
 * @example
 * ```typescript
 * import { cleanupStaleEntries, reconcileStateAtStartup } from './state-cleanup';
 *
 * // Clean up orphaned entries
 * const result = await cleanupStaleEntries({ dryRun: true });
 * console.log(`Would remove ${result.removed.length} entries`);
 *
 * // Reconcile state at startup
 * const reconcileResult = await reconcileStateAtStartup();
 * console.log(`Advanced ${reconcileResult.advanced.length} issues to merged`);
 * ```
 */

import { spawnSync } from "child_process";
import { StateManager } from "./state-manager.js";
import { isTerminalStatus } from "./state-schema.js";
import { checkPRMergeStatus, isIssueMergedIntoMain } from "./pr-status.js";

export interface CleanupOptions {
  /** State file path (default: .sequant/state.json) */
  statePath?: string;
  /** Only report what would be cleaned (don't modify) */
  dryRun?: boolean;
  /** Enable verbose logging */
  verbose?: boolean;
  /** Remove issues older than this many days */
  maxAgeDays?: number;
  /** Remove all orphaned entries (both merged and abandoned) in one step */
  removeAll?: boolean;
}

export interface CleanupResult {
  /** Whether cleanup was successful */
  success: boolean;
  /** Issues that were removed or would be removed */
  removed: number[];
  /** Issues that were marked as orphaned (abandoned) */
  orphaned: number[];
  /** Issues detected as merged PRs */
  merged: number[];
  /** Error message if failed */
  error?: string;
}

/**
 * Get list of active worktree paths
 */
function getActiveWorktrees(): string[] {
  const result = spawnSync("git", ["worktree", "list", "--porcelain"], {
    stdio: "pipe",
  });

  if (result.status !== 0) {
    return [];
  }

  const output = result.stdout.toString();
  const paths: string[] = [];

  for (const line of output.split("\n")) {
    if (line.startsWith("worktree ")) {
      paths.push(line.substring(9));
    }
  }

  return paths;
}

/**
 * Clean up stale and orphaned entries from workflow state
 *
 * - Checks GitHub to detect if associated PR was merged
 * - Orphaned entries with merged PRs get status "merged" and are removed automatically
 * - Orphaned entries without merged PRs get status "abandoned" (kept for review)
 * - Use removeAll to remove both merged and abandoned orphaned entries in one step
 * - Use maxAgeDays to remove old merged/abandoned issues
 */
export async function cleanupStaleEntries(
  options: CleanupOptions = {},
): Promise<CleanupResult> {
  const manager = new StateManager({
    statePath: options.statePath,
    verbose: options.verbose,
  });

  if (!manager.stateExists()) {
    return {
      success: true,
      removed: [],
      orphaned: [],
      merged: [],
    };
  }

  try {
    const state = await manager.getState();
    const removed: number[] = [];
    const orphaned: number[] = [];
    const merged: number[] = [];

    // Get list of active worktrees
    const activeWorktrees = getActiveWorktrees();

    for (const [issueNumStr, issueState] of Object.entries(state.issues)) {
      const issueNum = parseInt(issueNumStr, 10);

      // Check if worktree exists (if issue has one)
      if (
        issueState.worktree &&
        !activeWorktrees.includes(issueState.worktree)
      ) {
        if (options.verbose) {
          console.log(
            `🔍 Orphaned: #${issueNum} (worktree not found: ${issueState.worktree})`,
          );
        }

        // Check if this issue has a PR and if it's merged
        let prMerged = false;
        if (issueState.pr?.number) {
          if (options.verbose) {
            console.log(`   Checking PR #${issueState.pr.number} status...`);
          }
          const prStatus = checkPRMergeStatus(issueState.pr.number);
          prMerged = prStatus === "MERGED";
          if (options.verbose) {
            console.log(`   PR status: ${prStatus ?? "unknown"}`);
          }
        }

        if (!options.dryRun) {
          if (prMerged || issueState.status === "merged") {
            // Merged PRs are auto-removed
            merged.push(issueNum);
            removed.push(issueNum);
            if (options.verbose) {
              console.log(`   ✓ Merged PR detected, removing entry`);
            }
            delete state.issues[issueNumStr];
          } else if (issueState.status === "abandoned" || options.removeAll) {
            // Already abandoned or removeAll flag - remove it
            orphaned.push(issueNum);
            removed.push(issueNum);
            if (options.verbose) {
              console.log(`   ✓ Removing abandoned entry`);
            }
            delete state.issues[issueNumStr];
          } else {
            // Mark as abandoned (kept for review)
            orphaned.push(issueNum);
            issueState.status = "abandoned";
            if (!issueState.resolvedAt) {
              issueState.resolvedAt = new Date().toISOString();
            }
            if (options.verbose) {
              console.log(`   → Marked as abandoned (kept for review)`);
            }
          }
        } else {
          // Dry run - report what would happen
          if (prMerged || issueState.status === "merged") {
            merged.push(issueNum);
            removed.push(issueNum);
          } else if (issueState.status === "abandoned" || options.removeAll) {
            orphaned.push(issueNum);
            removed.push(issueNum);
          } else {
            orphaned.push(issueNum);
          }
        }
        continue;
      }

      // Check age for merged/abandoned issues
      if (
        options.maxAgeDays &&
        (issueState.status === "merged" || issueState.status === "abandoned")
      ) {
        const lastActivity = new Date(issueState.lastActivity);
        const ageDays =
          (Date.now() - lastActivity.getTime()) / (1000 * 60 * 60 * 24);

        if (ageDays > options.maxAgeDays) {
          removed.push(issueNum);

          if (options.verbose) {
            console.log(
              `🗑️  Stale: #${issueNum} (${Math.floor(ageDays)} days old)`,
            );
          }

          if (!options.dryRun) {
            delete state.issues[issueNumStr];
          }
        }
        continue;
      }

      // Force-clean: remove ALL resolved entries regardless of worktree/TTL
      if (isTerminalStatus(issueState.status)) {
        if (options.verbose) {
          console.log(`🧹 Resolved: #${issueNum} (${issueState.status})`);
        }

        if (issueState.status === "merged") {
          merged.push(issueNum);
        }

        removed.push(issueNum);

        if (!options.dryRun) {
          delete state.issues[issueNumStr];
        }
      }
    }

    // Save updated state
    if (!options.dryRun && (removed.length > 0 || orphaned.length > 0)) {
      await manager.saveState(state);
    }

    return {
      success: true,
      removed,
      orphaned,
      merged,
    };
  } catch (error) {
    return {
      success: false,
      removed: [],
      orphaned: [],
      merged: [],
      error: String(error),
    };
  }
}

export interface ReconcileOptions {
  /** State file path (default: .sequant/state.json) */
  statePath?: string;
  /** Enable verbose logging */
  verbose?: boolean;
}

export interface ReconcileResult {
  /** Whether reconciliation was successful */
  success: boolean;
  /** Issues that were advanced from ready_for_merge to merged */
  advanced: number[];
  /** Issues checked but still ready_for_merge */
  stillPending: number[];
  /** Error message if failed */
  error?: string;
}

/**
 * Lightweight state reconciliation at run start
 *
 * Checks issues in `ready_for_merge` state and advances them to `merged`
 * if their PRs are merged or their branches are in main.
 *
 * This prevents re-running already completed issues.
 *
 * @param options - Reconciliation options
 * @returns Result with lists of advanced and still-pending issues
 */
export async function reconcileStateAtStartup(
  options: ReconcileOptions = {},
): Promise<ReconcileResult> {
  const manager = new StateManager({
    statePath: options.statePath,
    verbose: options.verbose,
  });

  // Graceful degradation: if state file doesn't exist, skip
  if (!manager.stateExists()) {
    return {
      success: true,
      advanced: [],
      stillPending: [],
    };
  }

  try {
    const state = await manager.getState();
    const advanced: number[] = [];
    const stillPending: number[] = [];

    // Find issues in ready_for_merge state
    for (const [issueNumStr, issueState] of Object.entries(state.issues)) {
      if (issueState.status !== "ready_for_merge") {
        continue;
      }

      const issueNum = parseInt(issueNumStr, 10);
      let isMerged = false;

      // Check 1: If we have PR info, check PR status via gh
      if (issueState.pr?.number) {
        const prStatus = checkPRMergeStatus(issueState.pr.number);
        if (prStatus === "MERGED") {
          isMerged = true;
          if (options.verbose) {
            console.log(
              `  #${issueNum}: PR #${issueState.pr.number} is merged`,
            );
          }
        }
      }

      // Check 2: If no PR or PR check failed, check git for merged branch
      if (!isMerged) {
        isMerged = isIssueMergedIntoMain(issueNum);
        if (isMerged && options.verbose) {
          console.log(`  #${issueNum}: Branch merged into main (git check)`);
        }
      }

      if (isMerged) {
        // Advance state to merged
        issueState.status = "merged";
        issueState.lastActivity = new Date().toISOString();
        if (!issueState.resolvedAt) {
          issueState.resolvedAt = new Date().toISOString();
        }
        advanced.push(issueNum);
      } else {
        stillPending.push(issueNum);
      }
    }

    // Save state if any issues were advanced
    if (advanced.length > 0) {
      await manager.saveState(state);
    }

    return {
      success: true,
      advanced,
      stillPending,
    };
  } catch (error) {
    return {
      success: false,
      advanced: [],
      stillPending: [],
      error: String(error),
    };
  }
}

/**
 * Metrics writer for local workflow analytics
 *
 * Provides atomic writes (temp file + rename) to prevent corruption.
 * All data stays local - no network requests.
 *
 * @example
 * ```typescript
 * import { MetricsWriter } from './metrics-writer';
 *
 * const writer = new MetricsWriter();
 * await writer.recordRun({
 *   issues: [123, 124],
 *   phases: ['spec', 'exec', 'qa'],
 *   outcome: 'success',
 *   duration: 720,
 *   model: 'opus',
 *   flags: ['--chain'],
 *   metrics: { filesChanged: 9, linesAdded: 1800 }
 * });
 * ```
 */

import * as fs from "fs";
import * as path from "path";
import * as os from "os";
import {
  type Metrics,
  type MetricRun,
  type MetricPhase,
  type RunOutcome,
  type RunMetrics,
  MetricsSchema,
  METRICS_FILE_PATH,
  createEmptyMetrics,
  createMetricRun,
} from "./metrics-schema.js";

export interface MetricsWriterOptions {
  /** Path to metrics file (default: .sequant/metrics.json) */
  metricsPath?: string;
  /** Enable verbose logging */
  verbose?: boolean;
}

/**
 * Manages local workflow metrics collection
 */
export class MetricsWriter {
  private metricsPath: string;
  private verbose: boolean;
  private cachedMetrics: Metrics | null = null;

  constructor(options: MetricsWriterOptions = {}) {
    this.metricsPath = options.metricsPath ?? METRICS_FILE_PATH;
    this.verbose = options.verbose ?? false;
  }

  /**
   * Get the full path to the metrics file
   */
  getMetricsPath(): string {
    return this.metricsPath;
  }

  /**
   * Read the current metrics data
   *
   * Returns empty metrics if file doesn't exist.
   * Throws on parse errors.
   */
  async getMetrics(): Promise<Metrics> {
    // Return cached metrics if available
    if (this.cachedMetrics) {
      return this.cachedMetrics;
    }

    if (!fs.existsSync(this.metricsPath)) {
      const emptyMetrics = createEmptyMetrics();
      this.cachedMetrics = emptyMetrics;
      return emptyMetrics;
    }

    try {
      const content = fs.readFileSync(this.metricsPath, "utf-8");
      const parsed = JSON.parse(content);
      const metrics = MetricsSchema.parse(parsed);
      this.cachedMetrics = metrics;
      return metrics;
    } catch (error) {
      if (error instanceof SyntaxError) {
        throw new Error(`Invalid JSON in metrics file: ${error.message}`, {
          cause: error,
        });
      }
      throw error;
    }
  }

  /**
   * Write metrics to disk using atomic write
   *
   * Writes to a temp file first, then renames to prevent corruption
   * if the process is interrupted during write.
   */
  async saveMetrics(metrics: Metrics): Promise<void> {
    // Validate before writing
    MetricsSchema.parse(metrics);

    // Ensure directory exists
    const dir = path.dirname(this.metricsPath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }

    // Write to temp file first (atomic write pattern)
    const tempPath = path.join(
      os.tmpdir(),
      `sequant-metrics-${Date.now()}-${process.pid}.json`,
    );

    try {
      fs.writeFileSync(tempPath, JSON.stringify(metrics, null, 2));

      // Rename temp file to actual path (atomic on most systems)
      fs.renameSync(tempPath, this.metricsPath);

      // Update cache
      this.cachedMetrics = metrics;
    } catch (error) {
      // Clean up temp file on error
      if (fs.existsSync(tempPath)) {
        fs.unlinkSync(tempPath);
      }
      throw error;
    }
  }

  /**
   * Clear the cached metrics (forces re-read on next access)
   */
  clearCache(): void {
    this.cachedMetrics = null;
  }

  /**
   * Record a workflow run
   *
   * @param options - Run data to record
   */
  async recordRun(options: {
    issues: number[];
    phases: MetricPhase[];
    outcome: RunOutcome;
    duration: number;
    model?: string;
    flags?: string[];
    metrics?: Partial<RunMetrics>;
  }): Promise<MetricRun> {
    const metrics = await this.getMetrics();
    const run = createMetricRun(options);

    metrics.runs.push(run);
    await this.saveMetrics(metrics);

    if (this.verbose) {
      console.log(`📊 Recorded run: ${run.id.slice(0, 8)}... (${run.outcome})`);
    }

    return run;
  }

  /**
   * Get all runs
   */
  async getAllRuns(): Promise<MetricRun[]> {
    const metrics = await this.getMetrics();
    return metrics.runs;
  }

  /**
   * Get runs filtered by date range
   */
  async getRunsByDateRange(start: Date, end: Date): Promise<MetricRun[]> {
    const runs = await this.getAllRuns();
    return runs.filter((run) => {
      const runDate = new Date(run.date);
      return runDate >= start && runDate <= end;
    });
  }

  /**
   * Get the most recent N runs
   */
  async getRecentRuns(count: number): Promise<MetricRun[]> {
    const runs = await this.getAllRuns();
    // Runs are stored in chronological order, get the last N
    return runs.slice(-count);
  }

  /**
   * Check if metrics file exists
   */
  metricsExists(): boolean {
    return fs.existsSync(this.metricsPath);
  }

  /**
   * Delete the metrics file (for testing or user request)
   */
  async deleteMetrics(): Promise<void> {
    if (fs.existsSync(this.metricsPath)) {
      fs.unlinkSync(this.metricsPath);
      this.cachedMetrics = null;

      if (this.verbose) {
        console.log(`📊 Metrics deleted: ${this.metricsPath}`);
      }
    }
  }
}

// Export a default instance for convenience
let defaultWriter: MetricsWriter | null = null;

/**
 * Get the default metrics writer instance
 */
export function getMetricsWriter(
  options?: MetricsWriterOptions,
): MetricsWriter {
  if (!defaultWriter || options) {
    defaultWriter = new MetricsWriter(options);
  }
  return defaultWriter;
}

/**
 * Reset the default metrics writer (for testing)
 */
export function resetMetricsWriter(): void {
  defaultWriter = null;
}

