   * Set PR info on the current issue (call before completeIssue)
   */
  setPRInfo(prNumber: number, prUrl: string, issueNumber?: number): void {
    const issue = issueNumber
      ? (this.activeIssues.get(issueNumber) ?? this.currentIssue)
      : this.currentIssue;
