      const writer = new LogWriter();
      await writer.initialize(mockConfig);

      expect(() => {
        writer.completeIssue();
      }).toThrow("No current issue to complete");
    });

    it("should throw if writer not initialized", () => {
      const writer = new LogWriter();

      expect(() => {
        writer.completeIssue();
      }).toThrow("No run log");
    });
  });

  describe("finalize", () => {
